-- Acts 12: Herod''s Persecution, Peter''s Deliverance, and the Tyrant''s Death

-- 1. Chapter metadata
INSERT INTO chapters (book_id, chapter_number, overview, theme, key_word_original, key_word_meaning, outline)
SELECT b.id, 12,
  'Acts 12 is a study in two kings: Herod Agrippa I, the grandson of Herod the Great, and the unseen King of heaven who presides over his imprisoned servants. Eager to curry favor with the Jews, Herod seizes James the son of Zebedee and beheads him — the first martyrdom among the twelve — and then arrests Peter during the Passover, intending a public execution. But Luke inserts the pivot: "prayer was made without ceasing of the church unto God for him." On the very eve of his trial, with Peter chained between two soldiers and sixteen guards stationed, an angel of the Lord strikes Peter''s side, raises him, leads him past three watches and through an iron gate that opens of its own accord, and departs — leaving Peter, astonished, to find himself free on a Jerusalem street. He goes to the house of Mary the mother of John Mark, where many are gathered praying. The young servant Rhoda recognizes his voice at the door and, in her joy, forgets to open the gate but runs to tell the others — who refuse to believe her until Peter''s persistent knocking silences their unbelief. Peter recounts the deliverance, charges them to tell James (the Lord''s brother, now rising in Jerusalem leadership), and departs to another place. At daybreak, Herod, finding Peter gone, executes the guards and retires to Caesarea. There, at a civic festival, he accepts divine acclamation from the gathered crowd, is struck by the angel of the Lord, and is eaten of worms and dies. The chapter ends with a triumphant couplet: "But the word of God grew and multiplied." Luke closes by noting that Barnabas and Saul return from Jerusalem, bringing with them John Mark — a transition that sets up the first missionary journey. The chapter is Luke''s most vivid demonstration that earthly thrones rise and fall, persecutors strut and die, but the church prays and the word advances.',
  'The Tyrant Dies, the Church Prays, the Word Grows',
  'προσευχὴ',
  'prayer, supplication',
  '["Herod kills James and arrests Peter (vv.1-5)", "Peter delivered from prison by an angel (vv.6-11)", "The church''s unbelieving prayer answered at Mary''s house (vv.12-17)", "Herod investigates and relocates to Caesarea (vv.18-19)", "Herod''s death at Caesarea (vv.20-23)", "The word grows; Barnabas, Saul, and Mark return (vv.24-25)"]'::jsonb
FROM books b WHERE b.name = 'Acts'
ON CONFLICT (book_id, chapter_number) DO UPDATE SET
  overview = EXCLUDED.overview,
  theme = EXCLUDED.theme,
  key_word_original = EXCLUDED.key_word_original,
  key_word_meaning = EXCLUDED.key_word_meaning,
  outline = EXCLUDED.outline;

-- 2. Verses
INSERT INTO verses (chapter_id, verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
SELECT c.id, v.verse_number, v.kjv_text, v.original_text, v.transliteration, v.study_note, v.doctrinal_note
FROM chapters c JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'Now about that time Herod the king stretched forth his hands to vex certain of the church.',
   'Κατ’ ἐκεῖνον δὲ τὸν καιρὸν ἐπέβαλεν Ἡρῴδης ὁ βασιλεὺς τὰς χεῖρας κακῶσαί τινας τῶν ἀπὸ τῆς ἐκκλησίας.',
   'Kat'' ekeinon de ton kairon epebalen Hērōdēs ho basileus tas cheiras kakōsai tinas tōn apo tēs ekklēsias.',
   'Herod Agrippa I (reigned AD 41-44) ruled a united Judea under Claudius''s favor, the most territory held by a Herodian since his grandfather. Josephus (Ant. 19.343-350) confirms his calculated cultivation of Jewish religious sentiment. "Epebalen… tas cheiras" ("laid hands on") is OT persecution idiom.',
   'Political power often exploits religious piety for its own advancement. Herod persecutes not from theological conviction but from political calculation, revealing how rulers have always weaponized popular religion against Christ''s servants.'),
  (2, 'And he killed James the brother of John with the sword.',
   'ἀνεῖλεν δὲ Ἰάκωβον τὸν ἀδελφὸν Ἰωάννου μαχαίρῃ.',
   'Aneilen de Iakōbon ton adelphon Iōannou machairē.',
   'James the son of Zebedee is the first of the twelve martyred, fulfilling Jesus'' prophecy to the sons of Zebedee in Mark 10:39. Execution "with the sword" under Roman/Herodian jurisdiction usually meant beheading. Luke''s stark single sentence — uncommented — is theologically eloquent: the apostolic church knew both deliverance and martyrdom.',
   'God permits apostolic martyrdom as well as apostolic deliverance. The same faithfulness that delivers Peter takes James; divine sovereignty is never obligated to uniform outcomes, and the faith that honors God at the sword is as precious as the faith that walks out of prison.'),
  (3, 'And because he saw it pleased the Jews, he proceeded further to take Peter also. (Then were the days of unleavened bread.)',
   'ἰδὼν δὲ ὅτι ἀρεστόν ἐστιν τοῖς Ἰουδαίοις, προσέθετο συλλαβεῖν καὶ Πέτρον (ἦσαν δὲ αἱ ἡμέραι τῶν ἀζύμων)·',
   'Idōn de hoti areston estin tois Ioudaiois, prosetheto syllabein kai Petron (ēsan de hai hēmerai tōn azymōn);',
   '"Areston tois Ioudaiois" ("pleasing to the Jews") exposes the political motive. "Hēmerai tōn azymōn" ("days of unleavened bread") — Passover season, when Jerusalem''s population swelled with pilgrims; Herod plans maximum public impact. The echo of Jesus'' Passover arrest is deliberate.',
   'Herod''s plan to execute Peter at Passover deliberately echoes the Passion. But where the Father handed Jesus over to death, he here delivers Peter; the pattern of Passover deliverance is reasserted for the sake of the unfolding mission.'),
  (4, 'And when he had apprehended him, he put him in prison, and delivered him to four quaternions of soldiers to keep him; intending after Easter to bring him forth to the people.',
   'ὃν καὶ πιάσας ἔθετο εἰς φυλακήν, παραδοὺς τέσσαρσιν τετραδίοις στρατιωτῶν φυλάσσειν αὐτόν, βουλόμενος μετὰ τὸ πάσχα ἀναγαγεῖν αὐτὸν τῷ λαῷ.',
   'Hon kai piasas etheto eis phylakēn, paradous tessarsin tetradiois stratiōtōn phylassein auton, boulomenos meta to pascha anagagein auton tō laō.',
   '"Tessarsin tetradiois" ("four quaternions") — four squads of four soldiers, rotating the four watches of the night. Sixteen soldiers for one fisherman is a statement of Herod''s paranoia after Peter''s earlier miraculous prison release (5:19). The KJV''s "Easter" is a 17th-c. translational anachronism — Greek "pascha" means Passover.',
   'God is not intimidated by overwhelming security measures. The more elaborate the human bulwark against God''s purposes, the more spectacular his overturning of them; sixteen soldiers prove no match for one angel.'),
  (5, 'Peter therefore was kept in prison: but prayer was made without ceasing of the church unto God for him.',
   'ὁ μὲν οὖν Πέτρος ἐτηρεῖτο ἐν τῇ φυλακῇ· προσευχὴ δὲ ἦν ἐκτενῶς γινομένη ὑπὸ τῆς ἐκκλησίας πρὸς τὸν θεὸν περὶ αὐτοῦ.',
   'Ho men oun Petros etēreito en tē phylakē; proseuchē de ēn ektenōs ginomenē hypo tēs ekklēsias pros ton theon peri autou.',
   '"Ektenōs" ("without ceasing, fervently") literally "stretched out" — prayer that strains toward God. The hinge of the entire chapter: while Herod''s machinery clamps down, the church''s prayer reaches up. The narrative contrast sets the stage for the deliverance.',
   'The unseen, unregarded prayer of the church is the decisive political force in history. Kings tighten grips; congregations tighten intercessions; heaven answers the latter and overturns the former.'),
  (6, 'And when Herod would have brought him forth, the same night Peter was sleeping between two soldiers, bound with two chains: and the keepers before the door kept the prison.',
   'Ὅτε δὲ ἤμελλεν προαγαγεῖν αὐτὸν ὁ Ἡρῴδης, τῇ νυκτὶ ἐκείνῃ ἦν ὁ Πέτρος κοιμώμενος μεταξὺ δύο στρατιωτῶν δεδεμένος ἁλύσεσιν δυσίν, φύλακές τε πρὸ τῆς θύρας ἐτήρουν τὴν φυλακήν.',
   'Hote de ēmellen proagagein auton ho Hērōdēs, tē nykti ekeinē ēn ho Petros koimōmenos metaxy dyo stratiōtōn dedemenos halysesin dysin, phylakes te pro tēs thyras etēroun tēn phylakēn.',
   'Peter "sleeping" (koimōmenos) on the night before his execution is astonishing evidence of faith-rest (cf. Ps 4:8). Chained to two soldiers and with two more at the door, he should be sweating; instead he sleeps like a man under fatherly protection.',
   'Peace in mortal danger is the signature of deep faith. The Christian does not sleep because the threat is trivial but because the Father is faithful; gospel tranquility shines brightest on the eve of crucifying days.'),
  (7, 'And, behold, the angel of the Lord came upon him, and a light shined in the prison: and he smote Peter on the side, and raised him up, saying, Arise up quickly. And his chains fell off from his hands.',
   'καὶ ἰδοὺ ἄγγελος κυρίου ἐπέστη, καὶ φῶς ἔλαμψεν ἐν τῷ οἰκήματι· πατάξας δὲ τὴν πλευρὰν τοῦ Πέτρου ἤγειρεν αὐτὸν λέγων· ἀνάστα ἐν τάχει. καὶ ἐξέπεσαν αὐτοῦ αἱ ἁλύσεις ἐκ τῶν χειρῶν.',
   'Kai idou angelos kyriou epestē, kai phōs elampsen en tō oikēmati; pataxas de tēn pleuran tou Petrou ēgeiren auton legōn; anasta en tachei. Kai exepesan autou hai halyseis ek tōn cheirōn.',
   'The angel''s physical blow ("pataxas") is needed to wake the soundly sleeping Peter. "Phōs elampsen" ("light shone") — divine presence illumines the dungeon. Chains "fall off" without explanation; the deliverance is supernatural at every point.',
   'God''s deliverance is irresistible when he chooses to act. Locks, chains, and soldiers are equally powerless against divine intervention; when heaven sends an angel, nothing earthly can detain heaven''s servant.'),
  (8, 'And the angel said unto him, Gird thyself, and bind on thy sandals. And so he did. And he saith unto him, Cast thy garment about thee, and follow me.',
   'εἶπεν δὲ ὁ ἄγγελος πρὸς αὐτόν· ζῶσαι καὶ ὑπόδησαι τὰ σανδάλιά σου. ἐποίησεν δὲ οὕτως. καὶ λέγει αὐτῷ· περιβαλοῦ τὸ ἱμάτιόν σου καὶ ἀκολούθει μοι.',
   'Eipen de ho angelos pros auton; zōsai kai hypodēsai ta sandalia sou. Epoiēsen de houtōs. Kai legei autō; peribalou to himation sou kai akolouthei moi.',
   'The series of mundane commands — gird, put on sandals, wrap cloak — is deliberately unspectacular. The angel does not teleport Peter but walks him through ordinary dressing. Divine deliverance does not abolish creaturely sequence.',
   'Heavenly rescue still operates through earthly sequence. God delivers by commanding the rescued to take the next obedient step, not by abolishing human action but by directing it.'),
  (9, 'And he went out, and followed him; and wist not that it was true which was done by the angel; but thought he saw a vision.',
   'καὶ ἐξελθὼν ἠκολούθει, καὶ οὐκ ᾔδει ὅτι ἀληθές ἐστιν τὸ γινόμενον διὰ τοῦ ἀγγέλου, ἐδόκει δὲ ὅραμα βλέπειν.',
   'Kai exelthōn ēkolouthei, kai ouk ēdei hoti alēthes estin to ginomenon dia tou angelou, edokei de horama blepein.',
   'Peter''s confusion is candidly reported: he thought he was dreaming. The candid admission authenticates the account — invented heroics do not cast their protagonists as half-asleep.',
   'God''s works frequently outpace his servants'' understanding. Obedient following in apparent unreality is often the pattern of discipleship; clarity arrives retrospectively, after the deliverance is complete.'),
  (10, 'When they were past the first and the second ward, they came unto the iron gate that leadeth unto the city; which opened to them of his own accord: and they went out, and passed on through one street; and forthwith the angel departed from him.',
   'διελθόντες δὲ πρώτην φυλακὴν καὶ δευτέραν ἦλθαν ἐπὶ τὴν πύλην τὴν σιδηρᾶν τὴν φέρουσαν εἰς τὴν πόλιν, ἥτις αὐτομάτη ἠνοίγη αὐτοῖς, καὶ ἐξελθόντες προῆλθον ῥύμην μίαν, καὶ εὐθέως ἀπέστη ὁ ἄγγελος ἀπ’ αὐτοῦ.',
   'Dielthontes de prōtēn phylakēn kai deuteran ēlthan epi tēn pylēn tēn sidēran tēn pherousan eis tēn polin, hētis automatē ēnoigē autois, kai exelthontes proēlthon rhymēn mian, kai eutheōs apestē ho angelos ap'' autou.',
   '"Automatē" ("of its own accord") is the only NT use of this word. The same term is used in the LXX for the land that yields crop without plowing (Lev 25:5); divinity operates without mechanism. The angel withdraws once Peter is safely in the city.',
   'God provides what is necessary and no more. Angels assist in what cannot be done without them, then withdraw; believers are returned to the ordinary means of grace and human prudence once the crisis is past.'),
  (11, 'And when Peter was come to himself, he said, Now I know of a surety, that the Lord hath sent his angel, and hath delivered me out of the hand of Herod, and from all the expectation of the people of the Jews.',
   'καὶ ὁ Πέτρος ἐν ἑαυτῷ γενόμενος εἶπεν· νῦν οἶδα ἀληθῶς ὅτι ἐξαπέστειλεν κύριος τὸν ἄγγελον αὐτοῦ καὶ ἐξείλατό με ἐκ χειρὸς Ἡρῴδου καὶ πάσης τῆς προσδοκίας τοῦ λαοῦ τῶν Ἰουδαίων.',
   'Kai ho Petros en heautō genomenos eipen; nyn oida alēthōs hoti exapesteilen kyrios ton angelon autou kai exeilato me ek cheiros Hērōdou kai pasēs tēs prosdokias tou laou tōn Ioudaiōn.',
   '"En heautō genomenos" ("coming to himself") — the same phrase used of the prodigal son (Luke 15:17); Peter recognizes reality. His confession echoes Psalm 34:7 ("The angel of the LORD encampeth round about them that fear him") and Daniel 6:22 ("My God hath sent his angel").',
   'Divine deliverance is identified only in retrospect. The pilgrim often walks through miracles before he recognizes them; thanksgiving must follow perception, but perception is itself a gift of grace.'),
  (12, 'And when he had considered the thing, he came to the house of Mary the mother of John, whose surname was Mark; where many were gathered together praying.',
   'συνιδών τε ἦλθεν ἐπὶ τὴν οἰκίαν τῆς Μαρίας τῆς μητρὸς Ἰωάννου τοῦ ἐπικαλουμένου Μάρκου, οὗ ἦσαν ἱκανοὶ συνηθροισμένοι καὶ προσευχόμενοι.',
   'Synidōn te ēlthen epi tēn oikian tēs Marias tēs mētros Iōannou tou epikaloumenou Markou, hou ēsan hikanoi synēthroismenoi kai proseuchomenoi.',
   'Mary''s house appears to be a wealthier Jerusalem property (it had a gate, a servant, and enough rooms for "many" to gather). Her son John Mark will become the author of the Second Gospel and Paul''s companion. The household is evidently a hub of early Jerusalem Christianity.',
   'God raises households that sustain the mission. Mary''s home becomes a fixed place of prayer; generations of faithful laity, often female heads of households, have provided the physical infrastructure of the church''s intercessory life.'),
  (13, 'And as Peter knocked at the door of the gate, a damsel came to hearken, named Rhoda.',
   'κρούσαντος δὲ αὐτοῦ τὴν θύραν τοῦ πυλῶνος προσῆλθεν παιδίσκη ὑπακοῦσαι ὀνόματι Ῥόδη,',
   'Krousantos de autou tēn thyran tou pylōnos prosēlthen paidiskē hypakousai onomati Rhodē,',
   '"Rhodē" means "rose." The fact that Luke preserves the name of this servant girl — an otherwise socially invisible figure — suggests she was still known in the early church. The "pylōn" is the outer gate of a larger courtyard, distinct from the inner door.',
   'God preserves the names of the humble who witness his great works. The roll of gospel history is not filled only with apostles and prophets; a servant girl at a door has her name remembered in Scripture.'),
  (14, 'And when she knew Peter''s voice, she opened not the gate for gladness, but ran in, and told how Peter stood before the gate.',
   'καὶ ἐπιγνοῦσα τὴν φωνὴν τοῦ Πέτρου ἀπὸ τῆς χαρᾶς οὐκ ἤνοιξεν τὸν πυλῶνα, εἰσδραμοῦσα δὲ ἀπήγγειλεν ἑστάναι τὸν Πέτρον πρὸ τοῦ πυλῶνος.',
   'Kai epignousa tēn phōnēn tou Petrou apo tēs charas ouk ēnoixen ton pylōna, eisdramousa de apēngeilen hestanai ton Petron pro tou pylōnos.',
   'Rhoda''s joy-driven forgetfulness — she leaves Peter standing outside while rushing to tell — is a masterstroke of human-scale realism. The scene could be invented, but few hagiographers would have their hero awkwardly left knocking.',
   'Luke''s candid touches of human comedy authenticate sacred narrative. Scripture loses no dignity by recording domestic vignettes; on the contrary, the Spirit''s inspiration includes the grain of ordinary life in which he delights.'),
  (15, 'And they said unto her, Thou art mad. But she constantly affirmed that it was even so. Then said they, It is his angel.',
   'οἱ δὲ πρὸς αὐτὴν εἶπαν· μαίνῃ. ἡ δὲ διϊσχυρίζετο οὕτως ἔχειν. οἱ δὲ ἔλεγον· ὁ ἄγγελος ἐστὶν αὐτοῦ.',
   'Hoi de pros autēn eipan; mainē. Hē de diischyrizeto houtōs echein. Hoi de elegon; ho angelos estin autou.',
   '"Mainē" ("you are mad") — the prayerful company refuses to believe their prayer has been answered. "Ho angelos… autou" ("his angel") reflects a Jewish belief in guardian angels (cf. Matt 18:10). The irony is stinging: they would sooner believe a ghost than a deliverance.',
   'The church''s prayers often outrun her faith. God answers supplications that the supplicants cannot quite credit; unbelief is possible even among the faithful, and the Lord graciously overtakes it with evidence.'),
  (16, 'But Peter continued knocking: and when they had opened the door, and saw him, they were astonished.',
   'ὁ δὲ Πέτρος ἐπέμενεν κρούων· ἀνοίξαντες δὲ εἶδαν αὐτὸν καὶ ἐξέστησαν.',
   'Ho de Petros epemenen krouōn; anoixantes de eidan auton kai exestēsan.',
   '"Epemenen" ("kept on") — Peter''s persistent knocking forces the disputed issue. "Exestēsan" ("they were astonished, beside themselves") is the same word as the earthquake-trance vocabulary; joy has the same effect as prophetic rapture.',
   'Christ graciously overcomes the half-faith of his church. The Savior persists at the door with answers we have scarcely believed were possible; perseverance on his side meets hesitation on ours.'),
  (17, 'But he, beckoning unto them with the hand to hold their peace, declared unto them how the Lord had brought him out of the prison. And he said, Go shew these things unto James, and to the brethren. And he departed, and went into another place.',
   'κατασείσας δὲ αὐτοῖς τῇ χειρὶ σιγᾶν διηγήσατο αὐτοῖς πῶς ὁ κύριος αὐτὸν ἐξήγαγεν ἐκ τῆς φυλακῆς, εἶπέν τε· ἀπαγγείλατε Ἰακώβῳ καὶ τοῖς ἀδελφοῖς ταῦτα. καὶ ἐξελθὼν ἐπορεύθη εἰς ἕτερον τόπον.',
   'Kataseisas de autois tē cheiri sigan diēgēsato autois pōs ho kyrios auton exēgagen ek tēs phylakēs, eipen te; apangeilate Iakōbō kai tois adelphois tauta. Kai exelthōn eporeuthē eis heteron topon.',
   '"Iakōbō" is James the brother of Jesus (not James son of Zebedee, just killed). He emerges here as a leader of the Jerusalem church (cf. 15:13; 21:18; Gal 1:19; 2:9). "Heteron topon" ("another place") Luke leaves intentionally vague — prudent silence about Peter''s location protects him.',
   'Faithful discipleship includes prudent discretion. Not every gracious deliverance is broadcast; sometimes the proper response to divine rescue is quiet movement to a safer place, leaving the glory to God without advertising our own survival.'),
  (18, 'Now as soon as it was day, there was no small stir among the soldiers, what was become of Peter.',
   'Γενομένης δὲ ἡμέρας ἦν τάραχος οὐκ ὀλίγος ἐν τοῖς στρατιώταις, τί ἄρα ὁ Πέτρος ἐγένετο.',
   'Genomenēs de hēmeras ēn tarachos ouk oligos en tois stratiōtais, ti ara ho Petros egeneto.',
   '"Tarachos ouk oligos" ("no small stir") is Lukan litotes for extreme panic. Under Roman military law, guards whose prisoner escaped suffered the prisoner''s sentence (cf. 27:42). The soldiers face execution.',
   'The consequences of divine intervention often reverberate painfully in the lives of those bound to systems of injustice. God''s mercy to one can mean calamity for another; the moral weight of tyrannical regimes falls on their human instruments.'),
  (19, 'And when Herod had sought for him, and found him not, he examined the keepers, and commanded that they should be put to death. And he went down from Judaea to Caesarea, and there abode.',
   'Ἡρῴδης δὲ ἐπιζητήσας αὐτὸν καὶ μὴ εὑρὼν ἀνακρίνας τοὺς φύλακας ἐκέλευσεν ἀπαχθῆναι, καὶ κατελθὼν ἀπὸ τῆς Ἰουδαίας εἰς Καισάρειαν διέτριβεν.',
   'Hērōdēs de epizētēsas auton kai mē heurōn anakrinas tous phylakas ekeleusen apachthēnai, kai katelthōn apo tēs Ioudaias eis Kaisareian dietriben.',
   '"Apachthēnai" ("to be led away") is customary shorthand for capital execution. Herod''s retreat to Caesarea (the Roman provincial capital) is narrative preparation for the judgment scene that follows; the tyrant removes himself to the place of his own death.',
   'Wicked rulers tighten cruelty when humiliated, but God hems their course toward judgment. Herod''s murderous response is itself a step on his providential path to the divine verdict soon to fall upon him.'),
  (20, 'And Herod was highly displeased with them of Tyre and Sidon: but they came with one accord to him, and, having made Blastus the king''s chamberlain their friend, desired peace; because their country was nourished by the king''s country.',
   'Ἦν δὲ θυμομαχῶν Τυρίοις καὶ Σιδωνίοις· ὁμοθυμαδὸν δὲ παρῆσαν πρὸς αὐτόν, καὶ πείσαντες Βλάστον τὸν ἐπὶ τοῦ κοιτῶνος τοῦ βασιλέως ᾐτοῦντο εἰρήνην, διὰ τὸ τρέφεσθαι αὐτῶν τὴν χώραν ἀπὸ τῆς βασιλικῆς.',
   'Ēn de thymomachōn Tyriois kai Sidōniois; homothymadon de parēsan pros auton, kai peisantes Blaston ton epi tou koitōnos tou basileōs ētounto eirēnēn, dia to trephesthai autōn tēn chōran apo tēs basilikēs.',
   'Tyre and Sidon, coastal Phoenician cities, depended on Judean grain (cf. 1 Kgs 5:11; Ezek 27:17). "Blastus the king''s chamberlain" is literally "the one over the king''s bedchamber" — a high courtier. A trade embargo has reduced the cities to courtly bribery for peace.',
   'Political power and economic dependence entangle nations. Behind the glittering royal levee lie mundane realities of supply chains and palace intrigue; and over all, God superintends the moment he will expose the king''s vanity.'),
  (21, 'And upon a set day Herod, arrayed in royal apparel, sat upon his throne, and made an oration unto them.',
   'τακτῇ δὲ ἡμέρᾳ ὁ Ἡρῴδης ἐνδυσάμενος ἐσθῆτα βασιλικὴν καὶ καθίσας ἐπὶ τοῦ βήματος ἐδημηγόρει πρὸς αὐτούς·',
   'Taktē de hēmera ho Hērōdēs endysamenos esthēta basilikēn kai kathisas epi tou bēmatos edēmēgorei pros autous;',
   'Josephus (Ant. 19.343-350) confirms this scene in remarkable detail: a festival in Caesarea in honor of Claudius, Herod appearing in a robe of silver that flashed in the morning sun, an oration from the platform. Luke''s narrative and Josephus independently corroborate each other.',
   'Scripture and secular history confirm each other on the major public events of the apostolic age. The faith rests on verifiable occurrences, not mythic invention; historians like Josephus preserve the scaffolding Luke assumes.'),
  (22, 'And the people gave a shout, saying, It is the voice of a god, and not of a man.',
   'ὁ δὲ δῆμος ἐπεφώνει· θεοῦ φωνὴ καὶ οὐκ ἀνθρώπου.',
   'Ho de dēmos epephōnei; theou phōnē kai ouk anthrōpou.',
   'The Caesarea crowd, mostly Gentile, acclaims Herod in the language of imperial apotheosis. Josephus records that the flatterers "addressed him as a god." Herod does not refuse the acclaim, violating even Jewish monotheism in a public forum.',
   'Divine honor stolen by human rulers is the ancient idolatry that God decisively refuses. No ruler, however powerful, may accept worship; the glory of God is jealous beyond tolerance.'),
  (23, 'And immediately the angel of the Lord smote him, because he gave not God the glory: and he was eaten of worms, and gave up the ghost.',
   'παραχρῆμα δὲ ἐπάταξεν αὐτὸν ἄγγελος κυρίου ἀνθ’ ὧν οὐκ ἔδωκεν τὴν δόξαν τῷ θεῷ, καὶ γενόμενος σκωληκόβρωτος ἐξέψυξεν.',
   'Parachrēma de epataxen auton angelos kyriou anth'' hōn ouk edōken tēn doxan tō theō, kai genomenos skōlēkobrōtos exepsyxen.',
   'The same "angel of the Lord" who struck Peter to save him strikes Herod to destroy him. Josephus reports Herod suffering a gut disorder for five days before dying — likely hydatid cyst rupture with intestinal perforation and worm infestation, consistent with "skōlēkobrōtos" ("eaten of worms"). A chillingly precise cause of death echoing OT judgments on Antiochus IV (2 Macc 9:5-12).',
   'God strikes those who usurp his glory. The quick fate of Herod Agrippa — applauded as a god one moment, corpse the next — is the perennial warning to every would-be deity and every dazzled crowd.'),
  (24, 'But the word of God grew and multiplied.',
   'Ὁ δὲ λόγος τοῦ θεοῦ ηὔξανεν καὶ ἐπληθύνετο.',
   'Ho de logos tou theou ēuxanen kai eplēthyneto.',
   'One of Luke''s summary refrains (cf. 6:7; 12:24; 19:20). The contrast is total: Herod dies, the word grows. Earthly power fades; divine proclamation propagates. The two imperfect verbs connote continuous advance.',
   'The word of God is the only power that outlasts every earthly regime. Kingdoms crumble, tyrants expire, and empires recycle, but the gospel continues to grow and multiply as the uninterrupted operation of the eternal God.'),
  (25, 'And Barnabas and Saul returned from Jerusalem, when they had fulfilled their ministry, and took with them John, whose surname was Mark.',
   'Βαρναβᾶς δὲ καὶ Σαῦλος ὑπέστρεψαν εἰς Ἱερουσαλὴμ πληρώσαντες τὴν διακονίαν, συμπαραλαβόντες Ἰωάννην τὸν ἐπικληθέντα Μάρκον.',
   'Barnabas de kai Saulos hypestrepsan eis Hierousalēm plērōsantes tēn diakonian, symparalabontes Iōannēn ton epiklēthenta Markon.',
   'Manuscript traditions vary between "eis" and "ex" Jerusalem; the UBS reading "to Jerusalem" may be a scribal confusion, and context argues for return "from Jerusalem" back to Antioch. John Mark, Mary''s son (v.12) and Barnabas''s cousin (Col 4:10), is introduced — the future companion of missionaries and evangelist.',
   'God matures the next generation of workers alongside his current leaders. Young John Mark travels with Barnabas and Saul not as a project of the work but as a son being trained — the pattern of faithful succession.')
) AS v(verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
WHERE b.name = 'Acts' AND c.chapter_number = 12
ON CONFLICT (chapter_id, verse_number) DO UPDATE SET
  kjv_text = EXCLUDED.kjv_text,
  original_text = EXCLUDED.original_text,
  transliteration = EXCLUDED.transliteration,
  study_note = EXCLUDED.study_note,
  doctrinal_note = EXCLUDED.doctrinal_note;

-- 3. Word studies
INSERT INTO word_studies (verse_id, original_word, transliteration, strongs_number, meaning, word_order)
SELECT v.id, w.original_word, w.transliteration, w.strongs_number, w.meaning, w.word_order
FROM verses v JOIN chapters c ON v.chapter_id = c.id JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'κακῶσαί', 'kakōsai', 'G2559', 'To mistreat, harm, oppress. Aorist infinitive conveying harmful intent.', 1),
  (2, 'ἀνεῖλεν', 'aneilen', 'G337', 'Killed, took away. The standard verb for judicial execution.', 2),
  (2, 'μαχαίρῃ', 'machairē', 'G3162', 'Sword, dagger. Instrument of Roman-style beheading.', 3),
  (3, 'ἀρεστόν', 'areston', 'G701', 'Pleasing, acceptable. Herod''s criterion is popularity, not justice.', 4),
  (4, 'τετραδίοις', 'tetradiois', 'G5069', 'Quaternions, squads of four. Four such squads cover all four night watches.', 5),
  (4, 'πάσχα', 'pascha', 'G3957', 'Passover. KJV''s ''Easter'' is a 17th-century anachronism; here refers to the Jewish feast.', 6),
  (5, 'ἐτηρεῖτο', 'etēreito', 'G5083', 'Was being kept, guarded. Imperfect of continuous custody.', 7),
  (5, 'προσευχὴ', 'proseuchē', 'G4335', 'Prayer. The sustained, corporate, pleading intercession that moves the chapter.', 8),
  (5, 'ἐκτενῶς', 'ektenōs', 'G1619', 'Earnestly, fervently. Lit. ''stretched out''—prayer straining toward God with intensity.', 9),
  (6, 'κοιμώμενος', 'koimōmenos', 'G2837', 'Sleeping. Present participle of calm repose on the eve of scheduled execution.', 10),
  (7, 'ἐπέστη', 'epestē', 'G2186', 'Stood by, appeared suddenly. Characteristic verb of angelic arrival.', 11),
  (7, 'πατάξας', 'pataxas', 'G3960', 'Having struck. Physical action to wake the sleeping apostle.', 12),
  (7, 'ἐξέπεσαν', 'exepesan', 'G1601', 'Fell off. Chains drop without human agency.', 13),
  (10, 'αὐτομάτη', 'automatē', 'G844', 'Of itself, self-moved. Only NT use; the iron gate opens by divine agency alone.', 14),
  (10, 'σιδηρᾶν', 'sidēran', 'G4603', 'Iron. Emphasizes the strength of the barrier that nevertheless yields.', 15),
  (11, 'ἐξαπέστειλεν', 'exapesteilen', 'G1821', 'Sent out, dispatched. The Lord Himself is the Sender of the angel.', 16),
  (11, 'ἐξείλατό', 'exeilato', 'G1807', 'Delivered, rescued. OT verb of YHWH''s salvific rescues (Exod 3:8 LXX).', 17),
  (11, 'προσδοκίας', 'prosdokias', 'G4329', 'Expectation, eager anticipation. The Jewish crowd''s anticipated spectacle is thwarted.', 18),
  (12, 'συνηθροισμένοι', 'synēthroismenoi', 'G4867', 'Gathered together. Perfect participle of sustained corporate assembly.', 19),
  (13, 'παιδίσκη', 'paidiskē', 'G3814', 'Young female servant, maid. Household domestic worker.', 20),
  (14, 'χαρᾶς', 'charas', 'G5479', 'Joy. The emotion that overtakes Rhoda and makes her forget to open the gate.', 21),
  (15, 'μαίνῃ', 'mainē', 'G3105', 'You are mad. Present indicative of mania; the church''s incredulous rebuff.', 22),
  (15, 'διϊσχυρίζετο', 'diischyrizeto', 'G1340', 'Strongly insisted, confidently affirmed. Imperfect of sustained conviction.', 23),
  (16, 'ἐξέστησαν', 'exestēsan', 'G1839', 'Were astonished, beside themselves. The joyful counterpart to earlier prophetic rapture.', 24),
  (17, 'κατασείσας', 'kataseisas', 'G2678', 'Motioning with hand for silence. Same gesture as Paul (19:33; 21:40).', 25),
  (19, 'ἀνακρίνας', 'anakrinas', 'G350', 'Having examined, interrogated. Formal judicial investigation preceding sentence.', 26),
  (20, 'θυμομαχῶν', 'thymomachōn', 'G2371', 'Fiercely hostile, at war in temper. Only NT use; intensified verb for royal wrath.', 27),
  (20, 'κοιτῶνος', 'koitōnos', 'G2846', 'Bedchamber. Royal chamberlain''s purview; position of privileged access.', 28),
  (22, 'θεοῦ φωνὴ', 'theou phōnē', 'G2316/G5456', 'Voice of a god. Imperial apotheosis-language applied to a human ruler.', 29),
  (23, 'παραχρῆμα', 'parachrēma', 'G3916', 'Immediately, at once. Divine judgment without delay.', 30),
  (23, 'σκωληκόβρωτος', 'skōlēkobrōtos', 'G4662', 'Eaten by worms. Medically descriptive; echoes OT judgments (2 Macc 9:5-12 on Antiochus IV).', 31),
  (23, 'ἐξέψυξεν', 'exepsyxen', 'G1634', 'Breathed his last, expired. Same verb as Ananias/Sapphira (5:5,10).', 32),
  (24, 'ηὔξανεν', 'ēuxanen', 'G837', 'Was growing. Imperfect—continuous, organic multiplication of the word.', 33),
  (25, 'ὑπέστρεψαν', 'hypestrepsan', 'G5290', 'Returned. Same verb used of returning disciples throughout Luke-Acts.', 34)
) AS w(verse_number, original_word, transliteration, strongs_number, meaning, word_order)
WHERE b.name = 'Acts' AND c.chapter_number = 12 AND v.verse_number = w.verse_number
ON CONFLICT DO NOTHING;

